mapper.select:
SELECT COUNT(*) FROM appointment
WHERE status <> 'CANCELLED'
  AND start_time < #{end}
  AND end_time   > #{start}

SELECT a.id AS id, a.order_id AS orderId, a.main_product_id AS mainProductId, a.main_sku_id AS mainSkuId, a.start_time AS startTime, a.end_time AS endTime, a.total_duration AS totalDuration, a.pet_info AS petInfo, a.status AS status, a.create_time AS createTime, p.name AS mainProductName, p.cover_img AS mainProductCoverImg, s.spec_name AS mainSkuName, o.order_no AS orderNo, o.total_amount AS totalAmount, o.cancelled AS orderCancelled FROM appointment a JOIN product p ON p.id = a.main_product_id LEFT JOIN sku s ON s.id = a.main_sku_id JOIN orders o ON o.id = a.order_id WHERE a.user_id = #{userId}
AND a.status = #{status}
ORDER BY a.start_time DESC, a.id DESC

SELECT a.id AS id, a.order_id AS orderId, a.main_product_id AS mainProductId, a.main_sku_id AS mainSkuId, a.start_time AS startTime, a.end_time AS endTime, a.total_duration AS totalDuration, a.pet_info AS petInfo, a.status AS status, a.create_time AS createTime, p.name AS mainProductName, s.spec_name AS mainSkuName, o.order_no AS orderNo, o.customer_phone_snapshot AS customerPhone, o.customer_name AS customerName, o.total_amount AS totalAmount, o.cancelled AS orderCancelled FROM appointment a JOIN product p ON p.id = a.main_product_id LEFT JOIN sku s ON s.id = a.main_sku_id JOIN orders o ON o.id = a.order_id
AND a.start_time >= #{startTime}
AND a.start_time < #{endTime}
AND a.status = #{status}
AND (o.order_no LIKE CONCAT('%', #{keyword}, '%') OR o.customer_phone_snapshot LIKE CONCAT('%', #{keyword}, '%') OR o.customer_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY a.start_time ASC, a.id ASC

SELECT id, start_time, end_time FROM appointment
WHERE status <> 'CANCELLED'
  AND start_time < #{endTime}
  AND end_time   > #{startTime}
ORDER BY start_time ASC
